import React, { useEffect, useState } from "react";
import { mutateAppState, useAppState } from "./store";

const Highlight: React.FC = React.memo(() => {
  const busy = useAppState(o => o.busy) > 0;
  const highlight = useAppState(o => o.highlight);
  const highlightCaseSensitive = useAppState(o => o.highlightCaseSensitive);
  const [selectionExists, setSelectionExists] = useState(false);

  useEffect(() => {
    function handler() {
      const sel = window.getSelection();
      setSelectionExists(!sel?.isCollapsed);
    }

    document.addEventListener("selectionchange", handler);
    return () => document.removeEventListener("selectionchange", handler);
  }, []);

  function handleHighlightCaseSensitiveChange(e: React.ChangeEvent<HTMLInputElement>) {
    mutateAppState(d => {
      d.highlightCaseSensitive = e.target.checked;
    });
  }

  function handleUseSelectionClick() {
    mutateAppState(d => {
      d.highlight = window.getSelection() + "";
    });
  }

  function handleClearSelectionClick() {
    mutateAppState(d => {
      d.highlight = "";
    });
  }

  function handleKeyDown(e: React.KeyboardEvent<HTMLTextAreaElement>) {
    if (e.key === "Escape") {
      mutateAppState(d => {
        d.highlight = "";
      });
    }
  }

  return (
    <>
      <textarea
        id="highlight-input"
        value={highlight}
        placeholder="highlight regexp(s), one per line (Ctrl-/)"
        spellCheck={false}
        onKeyDown={handleKeyDown}
        onChange={e =>
          mutateAppState(d => {
            d.highlight = e.target.value;
          })
        }
      />
      <div>
        <div>
          <button disabled={highlight.length === 0} onClick={handleClearSelectionClick}>
            Clear
          </button>
        </div>
        <div>
          <button disabled={busy || !selectionExists} onClick={handleUseSelectionClick}>
            Use selection
          </button>
        </div>
        <div>
          <label>
            <input
              type="checkbox"
              checked={highlightCaseSensitive}
              onChange={handleHighlightCaseSensitiveChange}
            />
            Case sensitive
          </label>
        </div>
      </div>
    </>
  );
});

export default Highlight;
