import React, { useEffect, useRef } from "react";
import Day from "./Day";
import { formatDay } from "./utils";
import { TrackingItem } from "./types";
import { createGetItemsByDay, GetItemsByDayFunc } from "./memos";
import styles from "./Days.module.scss";
import { LOCAL_STORAGE_GAP_MIN_KEY, mutateAppState, useAppState } from "./store";
import Paginator from "./Paginator";

interface Props {
  items: TrackingItem[];
  filtered: boolean;
}

const DaysInner: React.FC<Props> = ({ items, filtered }) => {
  const busy = useAppState(o => o.busy) > 0;
  const sortAscending = useAppState(o => o.sortAscending);
  const gapMin = useAppState(o => o.gapMin);

  const getItemsByDayRef = useRef<GetItemsByDayFunc>();
  if (!getItemsByDayRef.current) {
    getItemsByDayRef.current = createGetItemsByDay("DaysInner");
  }

  const itemsByDay = getItemsByDayRef.current(items, sortAscending);

  const pageIndex = useAppState(o => o.pageIndex);
  const pageSize = 10;

  const offset = pageSize * pageIndex;
  const days = itemsByDay.slice(offset, offset + pageSize);

  useEffect(() => {
    localStorage[LOCAL_STORAGE_GAP_MIN_KEY] = gapMin;
  }, [gapMin]);

  return (
    <div className={styles.root}>
      <div className={styles.checkboxes}>
        <label>
          <input
            type="checkbox"
            disabled={busy}
            checked={sortAscending}
            onChange={e => {
              mutateAppState(d => {
                d.sortAscending = e.target.checked;
              });
            }}
          />
          Sort Ascending
        </label>
      </div>
      <div>
        <label>
          Gap min:
          <input
            type="number"
            value={gapMin}
            min={0}
            step={10}
            onChange={e =>
              mutateAppState(d => {
                d.gapMin = e.target.valueAsNumber || 0;
              })
            }
          />
        </label>
      </div>
      <div id="pagination-scroll-to" />
      <Paginator itemsByDay={itemsByDay} />
      <div className={styles.days}>
        {days.map(day => (
          <Day key={formatDay(day[0].date)} items={day} filtered={filtered} />
        ))}
      </div>
      <Paginator itemsByDay={itemsByDay} scrollOnChange={"#pagination-scroll-to"} />
    </div>
  );
};

const Days: React.FC<Props> = ({ items, filtered }) => {
  return items.length ? (
    <DaysInner items={items} filtered={filtered} />
  ) : (
    <div className={styles.nothing}>(nothing found)</div>
  );
};

export default React.memo(Days);
