import React, { Fragment, useEffect, useRef, useState } from "react";
import * as sheetapi from "./sheetapi";
import { sheetDateFormat, updateItem, updateItemKey, updateLocalStorageItems } from "./sheetapi";
import { format, formatISO, parse } from "date-fns";
import styles from "./Item.module.scss";
import { formatDiff } from "./utils";
import { makeGetHighlights } from "./memos";
import { getColor } from "./colors";
import { TrackingItem } from "./types";
import { mutateAppState, TagShowMode, useAppState, reduxStore } from "./store";
import produce from "immer";
import { resetObservable } from "./reset";
import { Subscription } from "rxjs";

interface Props {
  item: TrackingItem;
  tagShowMode: TagShowMode;
}

const ItemInner: React.FC<Props & { swatches: string[] }> = React.memo(
  ({ item, tagShowMode, swatches }) => {
    const referenceDate = useAppState(o => o.referenceDate);
    const busy = useAppState(o => o.busy) > 0;

    const [linger, setLinger] = useState(false);
    const [pendingDelete, setPendingDelete] = useState(false);

    const [editText, setEditText] = useState("");
    const [parsedEdit, setParsedEdit] = useState<{ text?: string; date?: Date; error: boolean }>({
      error: false,
    });

    const resetSubscription = useRef<Subscription>();

    useEffect(() => {
      if (editText && !resetSubscription.current) {
        resetSubscription.current = resetObservable.subscribe(() => setEditText(""));
      } else if (!editText && resetSubscription.current) {
        resetSubscription.current?.unsubscribe();
        resetSubscription.current = undefined;
      }
    }, [editText]);

    async function addAnother(text: string) {
      const date = new Date();
      setLinger(true);
      setTimeout(() => setLinger(false), 3000);
      sheetapi.addNote(date, text);
    }

    function handleMouseOverSpan(s: string) {
      if (/\S/.test(s)) {
        mutateAppState(d => {
          d.highlight = s.replace(/[^-A-Z0-9_]/i, "");
          if (d.filterUsingHighlight) {
            d.filterUsingHighlight = false;
            d.filter = "";
          }
        });
      }
    }

    function setReferenceTime(refTime: Date) {
      mutateAppState(d => {
        d.referenceDate = refTime;
      });
    }

    function parseEditText(input: string) {
      try {
        const splitAt = input.indexOf("\n");
        const date = parse(input.substr(0, splitAt).trim(), sheetDateFormat, new Date());
        if (Number.isNaN(date.getDate())) {
          setParsedEdit({ error: true });
          return;
        }
        const text = input.substr(splitAt + 1).trim();
        setParsedEdit({ text, date, error: false });
      } catch (e) {
        setParsedEdit({ error: true });
      }
    }

    async function handleActionChange(e: React.ChangeEvent<HTMLSelectElement>) {
      try {
        switch (e.target.value) {
          case "ANOTHER":
            addAnother(item.text);
            break;
          case "USE_TEXT":
            mutateAppState(d => {
              d.newItemText = item.text;
            });
            const scrollRoot = document.getElementById("scroll-root")!;
            scrollRoot.scrollTo(0, 0);
            const input = document.getElementById("new-item-input")! as HTMLTextAreaElement;
            input.focus();
            setTimeout(() => {
              input.setSelectionRange(0, 0);
            }, 0);
            break;
          case "EDIT":
            const s = `${format(item.date, sheetDateFormat)}\n${item.text}`;
            setEditText(s);
            parseEditText(s);
            break;
          case "DELETE":
            const prompt =
              `Delete row ${item.rowNum}?\n` + format(item.date, "h:mm aaaaa") + "\n" + item.text;
            setPendingDelete(true);
            setTimeout(async () => {
              try {
                if (window.confirm(prompt)) {
                  await sheetapi.deleteItem(item);
                  await sheetapi.loadData();
                }
              } finally {
                setPendingDelete(false);
              }
            }, 0);
            break;
        }
      } finally {
        e.target.value = "";
      }
    }

    if (editText) {
      async function saveEditedItem() {
        const newItemWithOldKey = produce(item, d => {
          d.date = parsedEdit.date!;
          d.text = parsedEdit.text!;
        });

        await updateItem(newItemWithOldKey);
        let found = false;
        mutateAppState(d => {
          for (let i = 0; i < d.trackingItems.length; i++) {
            if (d.trackingItems[i].key === item.key) {
              d.trackingItems[i].date = newItemWithOldKey.date;
              d.trackingItems[i].text = newItemWithOldKey.text;
              updateItemKey(d.trackingItems[i]);
              found = true;
              break;
            }
          }
        });
        if (!found) {
          throw Error("BUG: could not find item with key " + item.key);
        }
        updateLocalStorageItems(reduxStore.getState().trackingItems);
      }

      function handleKeyDown(e: React.KeyboardEvent<HTMLTextAreaElement>) {
        if (e.ctrlKey && e.key === "Enter") {
          saveEditedItem();
        } else if (e.key === "Escape") {
          setEditText("");
        }
      }

      function isChanged() {
        try {
          return (
            formatISO(parsedEdit.date!) !== formatISO(item.date) || parsedEdit.text !== item.text
          );
        } catch (e) {
          return false;
        }
      }

      function editTextChanged(text: string) {
        setEditText(text);
        parseEditText(text);
      }

      return (
        <div className={styles.editRoot}>
          <button disabled={busy} onClick={() => setEditText("")}>
            Cancel
          </button>
          <textarea
            className={parsedEdit.error ? styles.editError : ""}
            disabled={busy}
            value={editText}
            autoFocus={true}
            onKeyDown={handleKeyDown}
            onChange={e => editTextChanged(e.target.value)}
          />
          <button disabled={busy || !isChanged()} onClick={saveEditedItem}>
            Save
          </button>
        </div>
      );
    }

    let rootClass = styles.root;
    if (pendingDelete) {
      rootClass += " " + styles.pendingDelete;
    } else if (linger) {
      rootClass += " " + styles.linger;
    }

    return (
      <div className={rootClass}>
        <div className={styles.time} onClick={() => setReferenceTime(item.date)}>
          {format(item.date, "h:mm aaaaa")}
        </div>
        <div className={styles.timeDiff}>({formatDiff(item.date, referenceDate)})</div>
        <select
          defaultValue=""
          disabled={busy}
          onChange={handleActionChange}
          className={styles.actions}
        >
          <option disabled style={{ display: "none" }} />
          <option value="ANOTHER">Another {item.text}</option>
          <option value="USE_TEXT">Use Text</option>
          <option value="EDIT">Edit...</option>
          <option value="DELETE">Delete...</option>
        </select>
        <div className={styles.textAndTags}>
          <span className={styles.text}>
            <span style={{ marginRight: "0.5em" }}>
              {item.text.split(/\b/).map((s, i) => (
                <span key={i} onMouseMove={e => e.ctrlKey && handleMouseOverSpan(s)}>
                  {s}
                </span>
              ))}
            </span>
            {swatches.map((c, i) => (
              <Fragment key={i}>
                <span className={styles.swatch} style={{ backgroundColor: c }}>
                  {"             "}
                </span>
                <span> </span>
              </Fragment>
            ))}
            {item.tags &&
              tagShowMode === "ALL" &&
              item.tags.map((tag, i) => (
                <div key={i} className={styles.tag}>
                  {tag.quantity} {tag.unitName}
                </div>
              ))}
          </span>
        </div>
      </div>
    );
  }
);

const Item: React.FC<Props> = React.memo(props => {
  const highlight = useAppState(o => o.highlight);
  const highlightCaseSensitive = useAppState(o => o.highlightCaseSensitive);

  let swatches = makeGetHighlights(highlight, highlightCaseSensitive)
    .getHighlights(props.item.text)
    .map(getColor);
  const swatchesRef = useRef(swatches);

  if (swatchesRef.current !== swatches) {
    let allSame = false;
    if (swatchesRef.current.length === swatches.length) {
      allSame = true;
      for (let i = 0; i < swatches.length; i++) {
        if (swatchesRef.current[i] !== swatches[i]) {
          allSame = false;
          break;
        }
      }
    }

    if (!allSame) {
      swatchesRef.current = swatches;
    } else {
      swatches = swatchesRef.current;
    }
  }

  return <ItemInner swatches={swatches} {...props} />;
});

export default Item;
