import React from "react";
import { mutateAppState, useAppState } from "./store";
import styles from "./Days.module.scss";
import { TrackingItem } from "./types";

interface Props {
  itemsByDay: TrackingItem[][];
  scrollOnChange?: string;
}

const Paginator: React.FC<Props> = ({ scrollOnChange, itemsByDay }) => {
  const busy = useAppState(o => o.busy) > 0;
  const pageIndex = useAppState(o => o.pageIndex);
  const pageSize = 10;
  const maxPageIndex = Math.ceil(itemsByDay.length / pageSize) - 1;

  function setPageIndex(n: number) {
    mutateAppState(d => {
      d.pageIndex = n;
    });
  }

  function scrollIfNeeded() {
    if (scrollOnChange) {
      document.querySelector(scrollOnChange)!.scrollIntoView();
    }
  }

  function handleFirstPageClick() {
    setPageIndex(0);
    scrollIfNeeded();
  }

  function handlePrevPageClick() {
    setPageIndex(pageIndex - 1);
    scrollIfNeeded();
  }

  function handleNextPageClick() {
    setPageIndex(pageIndex + 1);
    scrollIfNeeded();
  }

  function handleLastPageClick() {
    setPageIndex(maxPageIndex);
    scrollIfNeeded();
  }

  return itemsByDay.length === 0 ? null : (
    <div className={styles.pagination}>
      <button onClick={handleFirstPageClick} disabled={busy || pageIndex === 0}>
        &lt;&lt;
      </button>
      <button onClick={handlePrevPageClick} disabled={busy || pageIndex === 0}>
        &lt;
      </button>
      <span>
        Page {pageIndex + 1} of {maxPageIndex + 1} ({itemsByDay.length} days)
      </span>
      <button onClick={handleNextPageClick} disabled={busy || pageIndex === maxPageIndex}>
        &gt;
      </button>
      <button onClick={handleLastPageClick} disabled={busy || pageIndex === maxPageIndex}>
        &gt;&gt;
      </button>
    </div>
  );
};

export default React.memo(Paginator);
