import { format } from "date-fns";
import Dexie from "dexie";
import { Tagger, TrackingItem } from "./types";
import { mutateAppState, reduxStore } from "./store";

const CLIENT_ID = "932720567325-1eedsiqf35ut37mnvue6crms40iolovr.apps.googleusercontent.com";
const spreadsheetId = new URLSearchParams(window.location.search).get("id") || "";

interface PendingNote {
  id?: number;
  timestamp: Date;
  text: string;
}

class NotesDB extends Dexie {
  pending: Dexie.Table<PendingNote, number>;

  constructor() {
    super("NotesDB");
    this.version(1).stores({
      pending: "++id, timestamp, text",
    });
    this.pending = this.table("pending");
  }
}

const db = new NotesDB();

const client = new Promise(resolve => {
  gapi.load("client:auth2", () => {
    resolve(
      gapi.client.init({
        clientId: CLIENT_ID,
        discoveryDocs: ["https://sheets.googleapis.com/$discovery/rest?version=v4"],
        scope: "https://www.googleapis.com/auth/spreadsheets",
      })
    );
  });
});

let sheetId: number | undefined; // always the first sheet for now

async function addPendingNotes() {
  const pendings = await db.pending.toArray();
  for (const pending of pendings) {
    await addNoteInternal(pending.timestamp, pending.text);
    await db.pending.delete(pending.id!);
  }
}

const handleSignInChange = API(async (signedIn: boolean) => {
  mutateAppState(d => {
    d.googleSignedIn = signedIn;
  });

  if (signedIn) {
    await addPendingNotes();
  }
});

client.then(
  API(async () => {
    const signedIn = gapi.auth2.getAuthInstance().isSignedIn.get();
    await handleSignInChange(signedIn);

    gapi.auth2.getAuthInstance().isSignedIn.listen(handleSignInChange);
  })
);

export function updateItemKey(item: TrackingItem) {
  item.key = item.date + " " + item.text;
}

try {
  const savedItems = JSON.parse(window.localStorage.getItem("items") || "[]") as TrackingItem[];
  for (const item of savedItems) {
    item.date = new Date(item.date);
    updateItemKey(item);
  }
  mutateAppState(d => {
    d.trackingItems = savedItems;
  });
} catch {}

function API<T extends any[], U>(func: (...args: T) => Promise<U>) {
  return async (...args: T): Promise<U> => {
    mutateAppState(d => {
      d.busy++;
    });

    try {
      return await func(...args);
    } finally {
      mutateAppState(d => {
        d.busy--;
      });
    }
  };
}

export const loadRange = API(async (rangeSpec?: { rowNum: number; count: number }) => {
  await client;

  let startRowNum = 1;
  let range = "A:B";
  if (rangeSpec) {
    startRowNum = rangeSpec.rowNum;
    range = `A${rangeSpec.rowNum}:B${rangeSpec.rowNum + rangeSpec.count}`;
  }

  const resp = await gapi.client.sheets.spreadsheets.values.get({
    spreadsheetId,
    range,
  });

  return (resp.result.values || [])
    .filter(row => row[0])
    .map(row => {
      const item: TrackingItem = {
        rowNum: startRowNum++,
        key: "",
        date: new Date(row[0]),
        text: row[1],
      };
      updateItemKey(item);
      return item;
    });
});

export const loadData = API(async () => {
  const items = await loadRange();

  mutateAppState(d => {
    d.trackingItems = items;
  });

  updateLocalStorageItems(items);

  getSheetId();
});

export function updateLocalStorageItems(items: TrackingItem[]) {
  window.localStorage.setItem("items", JSON.stringify(items));
}

async function getSheetId() {
  const resp = await gapi.client.sheets.spreadsheets.get({
    spreadsheetId,
    fields: "sheets.properties",
  });

  sheetId = resp.result.sheets![0].properties!.sheetId;
}

export const deleteItem = API(async (item: TrackingItem) => {
  if (sheetId === undefined) {
    await getSheetId();
  }

  const existingItems = await loadRange({ rowNum: item.rowNum, count: 1 });
  if (existingItems[0].key !== item.key) {
    throw Error(
      `Unable to delete. Please reload data. Key at row ${item.rowNum} is ${existingItems[0].key}`
    );
  }

  await gapi.client.sheets.spreadsheets.batchUpdate({
    spreadsheetId,
    resource: {
      requests: [
        {
          deleteDimension: {
            range: {
              sheetId,
              dimension: "ROWS",
              startIndex: item.rowNum - 1,
              endIndex: item.rowNum,
            },
          },
        },
      ],
    },
  });
});

export const sheetDateFormat = "M/d/yyyy H:mm:ss";

export const updateItem = API(async (item: TrackingItem) => {
  if (sheetId === undefined) {
    await getSheetId();
  }

  const existingItems = await loadRange({ rowNum: item.rowNum, count: 1 });
  if (existingItems[0].key !== item.key) {
    throw Error(
      `Unable to edit item. Please reload data. Key at row ${item.rowNum} is ${existingItems[0].key}`
    );
  }

  await gapi.client.sheets.spreadsheets.values.update({
    spreadsheetId,
    range: `A${item.rowNum}:B${item.rowNum}`,
    valueInputOption: "RAW",
    resource: {
      values: [[format(item.date, sheetDateFormat), item.text]],
    },
  });
});

async function addNoteInternal(date: Date, text: string) {
  const resp = await gapi.client.sheets.spreadsheets.values.append({
    spreadsheetId,
    range: "A:A",
    valueInputOption: "RAW",
    resource: {
      values: [[format(date, sheetDateFormat), text]],
    },
  });

  const range = resp.result.updates?.updatedRange!;
  const rowNum = parseInt(/!A(\d+)/.exec(range)![1], 10);

  mutateAppState(d => {
    const item = {
      rowNum,
      text,
      date,
      key: "",
    };
    updateItemKey(item);
    d.trackingItems.push(item);
  });

  window.localStorage.setItem("items", JSON.stringify(reduxStore.getState().trackingItems));
}

export const addNote = API(async (timestamp: Date, text: string) => {
  await client;

  const id = await db.pending.add({ timestamp, text });

  await addNoteInternal(timestamp, text);

  await db.pending.delete(id);
});

interface sheetInfo {
  id: number;
  title: string;
}

async function getSheets(): Promise<sheetInfo[]> {
  const resp = await gapi.client.sheets.spreadsheets.get({
    spreadsheetId,
    fields: "sheets.properties",
  });

  return resp.result.sheets!.map(
    o =>
      ({
        id: o.properties!.sheetId,
        title: o.properties!.title,
      } as sheetInfo)
  );
}

async function createSheet(title: string) {
  await gapi.client.sheets.spreadsheets.batchUpdate({
    spreadsheetId,
    resource: {
      requests: [
        {
          addSheet: {
            properties: {
              title,
            },
          },
        },
      ],
    },
  });
}

export interface Settings {
  taggers: Tagger[];
}

const settingsSheetTitle = "settings";

export const saveSettings = API(async (settings: Settings) => {
  const settingsSheet = (await getSheets()).find(o => o.title.toLowerCase() === settingsSheetTitle);
  if (!settingsSheet) {
    await createSheet(settingsSheetTitle);
  }

  await gapi.client.sheets.spreadsheets.values.update({
    spreadsheetId,
    range: "settings!A1",
    valueInputOption: "RAW",
    resource: {
      values: [[JSON.stringify(settings, null, 3)]],
    },
  });
});

export const loadSettings = API(async (): Promise<Settings> => {
  const resp = await gapi.client.sheets.spreadsheets.values.get({
    spreadsheetId,
    range: "settings!A1",
  });

  return JSON.parse(resp.result.values![0][0]) as Settings;
});
