import React, { useLayoutEffect } from "react";
import * as sheetapi from "./sheetapi";
import styles from "./Sheet.module.scss";
import Days from "./Days";
import Filter from "./Filter";
import Timeline from "./Timeline";
import { getFilteredItems, getFilterFromHighlight, getItemsInRange, getTaggedItems } from "./memos";
import NowTime from "./NowTime";
import NewItem from "./NewItem";
import { mutateAppState, useAppState } from "./store";
import GlobalShortcuts from "./GlobalShortcuts";
import Highlight from "./Highlight";
import Taggers from "./Taggers";
import { resetUI } from "./reset";

const Sheet: React.FC = () => {
  const trackingItems = useAppState(o => o.trackingItems);
  const taggers = useAppState(o => o.taggers);
  const selectedRange = useAppState(o => o.selectedRange);
  const busy = useAppState(o => o.busy) > 0;
  const filter = useAppState(o => o.filter);
  const filterCaseSensitive = useAppState(o => o.filterCaseSensitive);
  const filterShowFullDays = useAppState(o => o.filterShowFullDays);
  const filterUsingHighlight = useAppState(o => o.filterUsingHighlight);
  const highlight = useAppState(o => o.highlight);
  const highlightCaseSensitive = useAppState(o => o.highlightCaseSensitive);
  const showTimeline = useAppState(o => o.showTimeline);
  const googleSignedIn = useAppState(o => o.googleSignedIn);

  // useLayoutEffect instead of useEffect to eliminate flicker where the user can see it switch back to page 1
  const effectiveFilter = filterUsingHighlight ? highlight : filter;
  useLayoutEffect(() => {
    mutateAppState(d => {
      d.pageIndex = 0;
    });
  }, [selectedRange, effectiveFilter]);

  function handleAuthClick() {
    gapi.auth2.getAuthInstance().signIn();
  }

  function handleReload() {
    sheetapi.loadData();
  }

  function handleTimelineToggleClick() {
    mutateAppState(d => {
      d.showTimeline = !d.showTimeline;
      if (!d.showTimeline) {
        d.selectedRange = undefined;
      }
    });
  }

  const itemsToShow = getFilteredItems(
    getItemsInRange(getTaggedItems(trackingItems, taggers), selectedRange),
    filterUsingHighlight ? getFilterFromHighlight(highlight) : filter,
    filterUsingHighlight ? highlightCaseSensitive : filterCaseSensitive,
    filterShowFullDays
  );

  return (
    <div id="scroll-root" className={styles.root}>
      <GlobalShortcuts />
      <div className={styles.topBar}>
        <button disabled={busy} onClick={handleAuthClick}>
          Auth
        </button>
        <button disabled={busy} onClick={handleReload}>
          Load
        </button>
        <span>{googleSignedIn ? "Signed in" : "Not signed in"}</span>
        <button onClick={resetUI}>Reset</button>
      </div>
      <div className={styles.controlBar}>
        <NewItem />
      </div>
      <div className={styles.controlBar}>
        <Highlight />
      </div>
      <div className={styles.controlBar}>
        <button onClick={handleTimelineToggleClick}>Toggle Timeline</button>
        <NowTime />
      </div>
      <div className={styles.timeline}>{showTimeline && <Timeline items={trackingItems} />}</div>
      <Filter />
      <Taggers />
      <Days
        items={itemsToShow}
        filtered={!filterShowFullDays && itemsToShow.length !== trackingItems.length}
      />
    </div>
  );
};

export default Sheet;
