import React, { useEffect, useState } from "react";
import styles from "./Sheet.module.scss";
import { formatDiff } from "./utils";
import { mutateAppState, useAppState } from "./store";

const NowTime: React.FC = () => {
  const referenceDate = useAppState(o => o.referenceDate);

  const [nowTime, setNowTime] = useState(new Date());

  useEffect(() => {
    const interval = window.setInterval(() => {
      setNowTime(new Date());
    }, 1000);
    return () => clearInterval(interval);
  }, []);

  function handleResetRefTimeClick() {
    mutateAppState(d => {
      d.referenceDate = new Date();
    });
  }

  return (
    <>
      <button onClick={handleResetRefTimeClick}>Set ref. time to now</button>
      <span className={styles.nowTimeDiff}>{formatDiff(nowTime, referenceDate)}</span>
    </>
  );
};

export default NowTime;
