import React, { memo, useRef, useState } from "react";
import styles from "./Timeline.module.scss";
import { format, addDays, differenceInCalendarDays, startOfDay } from "date-fns";
import { makeGetHighlights, createGetItemsByDay, GetItemsByDayFunc } from "./memos";
import { getColor } from "./colors";
import { arc } from "d3-shape";
import { TrackingItem } from "./types";
import { mutateAppState, useAppState } from "./store";

interface Props {
  items: TrackingItem[];
}

interface ColoredDay {
  date: Date;
  dayNum: number;
  x: number;
  y: number;
  colors: string[];
}

const TimelineInner: React.FC<Props> = ({ items }) => {
  const highlight = useAppState(o => o.highlight);
  const highlightCaseSensitive = useAppState(o => o.highlightCaseSensitive);

  const { getHighlights, highlightPatterns } = makeGetHighlights(highlight, highlightCaseSensitive);

  const getItemsByDayRef = useRef<GetItemsByDayFunc>();
  if (!getItemsByDayRef.current) {
    getItemsByDayRef.current = createGetItemsByDay("TimelineInner");
  }

  const itemsByDay = getItemsByDayRef.current(items, false);

  const firstDay = itemsByDay[0][0].date;
  const firstDayNum = dayNum(firstDay);

  function dayNum(d: Date) {
    return (d.getDay() + 6) % 7;
  }

  function dayOffset(d: Date): number {
    return differenceInCalendarDays(firstDay, d);
  }

  const size = 40;

  let maxMatchIndex = -1;

  const coloredDays: ColoredDay[] = itemsByDay.map(day => {
    const date = day[0].date;
    const offset = dayOffset(date);

    const colors: string[] = [];
    const seenMatchIndexes = new Set<number>();
    for (const item of day) {
      const matches = getHighlights(item.text);
      for (const matchIndex of matches) {
        if (matchIndex !== null && !seenMatchIndexes.has(matchIndex)) {
          colors.push(getColor(matchIndex));
          seenMatchIndexes.add(matchIndex);
          maxMatchIndex = Math.max(maxMatchIndex, matchIndex);
        }
      }
    }

    if (colors.length === 0) {
      colors.push("white");
    }

    colors.sort();

    const x = Math.floor((offset + (6 - firstDayNum)) / 7) * size + 2;
    const y = size * (6 - dayNum(date)) + 2 + (dayNum(date) < 5 ? 8 : 0);

    return {
      date,
      dayNum: dayNum(date),
      x,
      y,
      colors,
    };
  });

  const maxX = coloredDays.map(d => d.x).reduce((a, b) => Math.max(a, b));

  let labels: Array<{ text: string; x: number }> = [];
  let monday = addDays(firstDay, -firstDayNum);
  const pastEnd = addDays(coloredDays[coloredDays.length - 1].date, -7);
  let x = 0;
  while (monday > pastEnd) {
    labels.push({ text: format(monday, "LLL d"), x });
    x += size;
    monday = addDays(monday, -7);
  }

  const [sel1, setSel1] = useState<ColoredDay | undefined>();
  const selectedDays = useAppState(d => d.selectedRange);

  function handleDayClick(e: React.MouseEvent<SVGGElement, MouseEvent>, day: ColoredDay) {
    e.stopPropagation();

    if (!sel1) {
      setSel1(day);
    } else {
      setSel1(undefined);
      const selectedRange = [sel1, day]
        .map(o => startOfDay(o.date))
        .sort((a, b) => a.valueOf() - b.valueOf());
      selectedRange[1] = addDays(selectedRange[1], 1);
      mutateAppState(d => {
        d.selectedRange = selectedRange;
      });
    }
  }

  function handleStrayClick() {
    if (!sel1) {
      mutateAppState(d => {
        d.selectedRange = undefined;
      });
    }
    setSel1(undefined);
  }

  return (
    <>
      <div className={styles.swatches}>
        {highlightPatterns.map((pattern, i) => (
          <span key={i} style={{ backgroundColor: getColor(i) }}>
            {pattern}
          </span>
        ))}
        &nbsp;
      </div>
      <div className={styles.root} onClick={handleStrayClick}>
        <svg style={{ height: 7 * size + 80, width: maxX + 100 }}>
          {labels.map(o => (
            <g
              key={o.text}
              transform={`translate(${o.x + size / 2 + 33},${size * 7 + 26}) rotate(-45 )`}
            >
              <text textAnchor="end">{o.text}</text>
            </g>
          ))}
          {coloredDays.map((day, i) => (
            <g
              key={i}
              transform={`translate(${day.x + size / 2 + 20},${day.y + size / 2})`}
              onClick={e => handleDayClick(e, day)}
            >
              <title>{day.date.toString()}</title>
              {sel1?.date === day.date && (
                <rect
                  className={styles.sel1}
                  x={-size / 2}
                  y={-size / 2}
                  width={size}
                  height={size}
                />
              )}
              {selectedDays && day.date >= selectedDays[0] && day.date <= selectedDays[1] && (
                <rect
                  className={styles.selRange}
                  x={-size / 2}
                  y={-size / 2}
                  width={size}
                  height={size}
                />
              )}
              {day.colors.map((c, i) => (
                <path
                  d={
                    arc()({
                      innerRadius: 0,
                      outerRadius: size / 2 - 1,
                      startAngle: ((Math.PI * 2) / day.colors.length) * i,
                      endAngle: ((Math.PI * 2) / day.colors.length) * (i + 1),
                    })!
                  }
                  key={i}
                  fill={c}
                  stroke="black"
                  strokeOpacity="0.2"
                />
              ))}
              {day.date.getDate() === 1 && (
                <circle r={size / 2 - 2} className={styles.firstOfMonth} />
              )}
            </g>
          ))}
        </svg>
      </div>
    </>
  );
};

const Timeline: React.FC<Props> = memo(({ items }) => {
  if (items.length === 0) {
    return null;
  }

  return <TimelineInner items={items} />;
});

export default Timeline;
