import React, { useEffect } from "react";
import { resetUI } from "./reset";
import { mutateAppState } from "./store";

const GlobalShortcuts: React.FC = () => {
  useEffect(() => {
    let prevKey: string | undefined;
    function handler(e: KeyboardEvent) {
      if (e.key === "Escape") {
        if (prevKey === "Escape") {
          resetUI();
          prevKey = undefined;
          return;
        }
      }

      prevKey = e.key;

      if (e.key === "/" && e.ctrlKey) {
        const input = document.getElementById("highlight-input") as HTMLInputElement | null;
        if (input) {
          input.focus();
          input.select();
          e.preventDefault();
        }
      }

      if (
        !document.activeElement ||
        (document.activeElement.tagName !== "TEXTAREA" &&
          (document.activeElement.tagName !== "INPUT" ||
            document.activeElement.getAttribute("type") !== "text"))
      ) {
        if (e.key === "[" || e.key === "]") {
          const dayElems = Array.from(document.querySelectorAll(".day"));
          if (e.key === "[") {
            dayElems.reverse();
          }

          const scrollRoot = document.getElementById("scroll-root")!;
          const currentScrollTop = scrollRoot.scrollTop;

          for (const dayElem of dayElems) {
            const dayTop = dayElem.getBoundingClientRect().top;
            if ((e.key === "[" && dayTop < -1) || (e.key === "]" && dayTop > 1)) {
              dayElem.scrollIntoView();
              if (scrollRoot.scrollTop === currentScrollTop) {
                // scroll didn't change because the day doesn't have enough items to be able to have its header at the top
                break;
              } else {
                return;
              }
            }
          }

          // at the beginning/end (or can't scroll down any further). move to prev/next page.
          if (e.key === "]") {
            mutateAppState(d => {
              d.pageIndex++;
            });
            // handle falling off the end
            // TODO: do this without bouncing back and forth
            const firstDay = document.querySelector(".day");
            if (firstDay) {
              firstDay.scrollIntoView();
            } else {
              mutateAppState(d => {
                d.pageIndex--;
              });
            }
          } else if (e.key === "[") {
            let changed = false;
            mutateAppState(d => {
              if (d.pageIndex > 0) {
                changed = true;
                d.pageIndex--;
              }
            });
            if (changed) {
              document.querySelector(".day:last-of-type")!.scrollIntoView();
            }
          }
        }
      }
    }

    window.addEventListener("keydown", handler);
    return function () {
      window.removeEventListener("keydown", handler);
    };
  }, []);

  return null;
};

export default GlobalShortcuts;
