import React from "react";
import { format, differenceInCalendarDays, differenceInMinutes } from "date-fns";
import styles from "./Day.module.scss";
import Item from "./Item";
import { Tag, Tagger, TrackingItem } from "./types";
import { useAppState } from "./store";

interface Props {
  items: TrackingItem[];
  filtered: boolean;
}

const Day: React.FC<Props> = ({ items, filtered }) => {
  const formattedDate = format(items[0].date, "yyyy-MM-dd EEE");
  const daysAgo = differenceInCalendarDays(new Date(), items[0].date);
  const tagShowMode = useAppState(o => o.tagShowMode);
  const taggers = useAppState(o => o.taggers);
  const gapMin = useAppState(o => o.gapMin);

  function handleHeaderClick(e: React.MouseEvent<HTMLDivElement>) {
    const scrollRoot = document.getElementById("scroll-root")!;
    scrollRoot.scrollTo(0, 0);
    e.preventDefault();
    e.stopPropagation();
  }

  let tagTotals: Tag[] | undefined;
  if (tagShowMode !== "NONE") {
    tagTotals = calculateTagTotals(items, taggers);
  }

  return (
    <div className={styles.root + " day"}>
      <div className={styles.dayHeader} onClick={handleHeaderClick}>
        {formattedDate},{" "}
        {daysAgo === 0 ? "today" : daysAgo === 1 ? "yesterday" : daysAgo + " days ago"}
      </div>
      {tagTotals && tagTotals.length > 0 && (
        <div className={styles.tagTotals}>
          {tagTotals.map(tag => (
            <div key={tag.unitName} className={styles.tag}>
              {tag.quantity} {tag.unitName}
            </div>
          ))}
        </div>
      )}
      {tagShowMode !== "DAY_SUMMARIES_ONLY" &&
        items.map((item, i) => (
          <>
            <Item key={item.key} item={item} tagShowMode={tagShowMode} />
            {!filtered && gapMin > 0 && i + 1 < items.length && gap(gapMin, item, items[i + 1])}
          </>
        ))}
    </div>
  );
};

export default React.memo(Day);

function gap(gapMin: number, a: TrackingItem, b: TrackingItem) {
  const diff = Math.abs(differenceInMinutes(a.date, b.date));
  if (diff < gapMin) return null;
  const height = diff / 2;

  return (
    <>
      <div className={styles.gap1} style={{ height }}>
        &nbsp;
      </div>
      <div className={styles.gap2} style={{ height }}>
        &nbsp;
      </div>
    </>
  );
}

function calculateTagTotals(items: TrackingItem[], taggers: Tagger[]): Tag[] {
  const totals = new Map<string, number>();
  for (const item of items) {
    if (!item.tags) continue;

    for (const tag of item.tags) {
      const current = totals.get(tag.unitName) || 0;
      totals.set(tag.unitName, current + tag.quantity);
    }
  }

  const results: Tag[] = [];
  for (const tagger of taggers) {
    const quantity = totals.get(tagger.unitName);
    if (typeof quantity === "number") {
      results.push({
        unitName: tagger.unitName,
        quantity,
      });
    }
  }

  return results;
}
