import { Tagger, TrackingItem } from "./types";
import { formatDay } from "./utils";
import memoizeOne from "memoize-one";
import produce from "immer";

function memo<T extends (...args: any[]) => any>(name: string, fn: T): T {
  return memoizeOne(function (...args: any[]) {
    try {
      console.time(name);
      return fn(...args);
    } finally {
      console.timeEnd(name);
    }
  }) as unknown as T;
}

export const makeGetHighlights = memo(
  "makeGetHighlights",
  (patternSpec: string, caseSensitive: boolean) => {
    let patterns: string[] = [];
    let regexps: RegExp[] = [];
    if (patternSpec) {
      try {
        for (const pattern of patternSpec.split("\n")) {
          if (pattern) {
            const re = new RegExp(pattern, caseSensitive ? "" : "i");
            patterns.push(pattern);
            regexps.push(re);
          }
        }
      } catch (e) {}
    }
    return {
      highlightPatterns: patterns,
      getHighlights: (s: string) => {
        const result: number[] = [];
        for (let i = 0; i < regexps.length; i++) {
          if (regexps[i].test(s)) {
            result.push(i);
          }
        }
        return result;
      },
    };
  }
);

export type GetItemsByDayFunc = (items: TrackingItem[], sortAscending: boolean) => TrackingItem[][];

export const createGetItemsByDay = (usageName: string): GetItemsByDayFunc => {
  return memo("getItemsByDay: " + usageName, (items: TrackingItem[], sortAscending: boolean) => {
    const groups = new Map<string, TrackingItem[]>();
    for (const item of items) {
      const day = formatDay(item.date);
      let forDay = groups.get(day);
      if (!forDay) {
        forDay = [];
        groups.set(day, forDay);
      }
      forDay.push(item);
    }

    const days = Array.from(groups.keys());
    days.sort();

    if (!sortAscending) {
      days.reverse();
    }

    return days.map(day =>
      groups.get(day)!.sort((a, b) => {
        if (sortAscending) {
          return a.date.valueOf() - a.date.valueOf();
        } else {
          return b.date.valueOf() - a.date.valueOf();
        }
      })
    );
  });
};

export const getItemsInRange = memo(
  "getItemsInRange",
  (items: TrackingItem[], selectedRange: Date[] | undefined) => {
    if (!selectedRange) {
      return items;
    }

    return items.filter(item => item.date >= selectedRange[0] && item.date < selectedRange[1]);
  }
);

export const getFilteredItems = memo(
  "getFilteredItems",
  (items: TrackingItem[], regex: string, caseSensitive, showFullDays: boolean) => {
    if (!regex) {
      return items;
    }
    try {
      const re = new RegExp(regex, caseSensitive ? "" : "i");

      let filtered = items.filter(o => re.test(o.text));
      if (showFullDays) {
        const days = new Set<string>();
        for (const item of filtered) {
          days.add(formatDay(item.date));
        }

        filtered = items.filter(o => days.has(formatDay(o.date)));
      }

      return filtered;
    } catch (e) {
      return [];
    }
  }
);

export const getFilterFromHighlight = memo("getFilterFromHighlight", (regex: string) => {
  return regex
    .split(/\n+/)
    .filter(s => !/^\s*$/.test(s))
    .join("|");
});

export const getTaggedItems = memo("getTaggedItems", (items: TrackingItem[], taggers: Tagger[]) => {
  return produce(items, itemsDraft => {
    for (const tagger of taggers) {
      if (!tagger.includePattern) continue;

      try {
        const include = new RegExp(tagger.includePattern, "i");
        let exclude: RegExp | undefined;
        if (tagger.excludePattern) {
          exclude = new RegExp(tagger.excludePattern, "i");
        }

        for (const item of itemsDraft) {
          if (exclude && exclude.test(item.text)) continue;

          const m = include.exec(item.text);
          if (!m) continue;

          let quantity = 1;
          for (let i = 1; i < m.length; i++) {
            if (m[i]) {
              quantity = Number.parseFloat(m[i]);
              break;
            }
          }

          if (!item.tags) {
            item.tags = [];
          }
          item.tags.push({ quantity, unitName: tagger.unitName });
        }
      } catch (e) {}
    }
  });
});
