import React, { useEffect, useState } from "react";
import { LOCAL_STORAGE_TEXT_KEY, mutateAppState, useAppState } from "./store";
import { add as dateFnsAdd, set as dateFnsSet } from "date-fns";
import * as sheetapi from "./sheetapi";

const NewItem: React.FC = () => {
  const [addInProgress, setAddInProgress] = useState(false);
  const newItemText = useAppState(o => o.newItemText);

  useEffect(() => {
    localStorage[LOCAL_STORAGE_TEXT_KEY] = newItemText;
  }, [newItemText]);

  function handleAddClick() {
    let s = newItemText.replace(/^\s+|\s+$/g, "");
    if (!s) return;

    let date = new Date();

    if (s[0] === "@") {
      if (s[1] === "-" || s[1] === "+") {
        const m = /^@([-+]\d+)\s+(.+)$/.exec(s);
        if (!m) {
          window.alert("Invalid relative time designation");
          return;
        }

        s = m[2];
        date = dateFnsAdd(date, { minutes: parseInt(m[1], 10) });
      } else {
        const m = /^@([01]?\d):?([0-5]\d)\s*?(am?|pm?)\s+(.+)$/i.exec(s);
        if (!m) {
          window.alert("Invalid time designation");
          return;
        }

        const isAm = m[3][0].toLowerCase() === "a";
        s = m[4];
        let hours = parseInt(m[1], 10);
        if (isAm && hours === 12) {
          hours = 0;
        } else if (!isAm && hours !== 12) {
          hours += 12;
        }
        date = dateFnsSet(date, {
          hours,
          minutes: parseInt(m[2], 10),
          seconds: 0,
        });
      }
    }

    setAddInProgress(true);
    sheetapi
      .addNote(date, s)
      .then(() => {
        mutateAppState(d => {
          d.newItemText = "";
        });
      })
      .finally(() => setAddInProgress(false));
  }

  function handleKeyDown(e: React.KeyboardEvent<HTMLTextAreaElement>) {
    if (e.ctrlKey && e.key === "Enter") handleAddClick();
  }

  return (
    <>
      <button
        disabled={newItemText.length === 0}
        onClick={() =>
          mutateAppState(d => {
            d.newItemText = "";
          })
        }
      >
        Clear
      </button>
      <textarea
        id="new-item-input"
        disabled={addInProgress}
        value={newItemText}
        onChange={e =>
          mutateAppState(d => {
            d.newItemText = e.target.value;
          })
        }
        onKeyDown={handleKeyDown}
      />
      <button disabled={addInProgress || newItemText.length === 0} onClick={handleAddClick}>
        Add
      </button>
    </>
  );
};

export default NewItem;
